import Router from './components/routes';
import LanguageProvider from './context/language';
import ThemeContextProvider from './context/theme';

function App() {
	return (
		<div>
			<ThemeContextProvider>
				<LanguageProvider>
					<div>
						<Router />
					</div>
				</LanguageProvider>
			</ThemeContextProvider>
		</div>
	);
}

export default App;
